import{_ as s,C as l,o as i,c as r,ae as a,j as t,a as n,E as d}from"./chunks/framework.CbfcRfVi.js";const u="/playstation-linux-tutorial/screenshots/psfree-payloads.jpg",c="/playstation-linux-tutorial/screenshots/ps4boot-payloads.png",k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"_includes/payloads.md","filePath":"_includes/payloads.md","lastUpdated":1777892371000}'),p={name:"_includes/payloads.md"},h={class:"details custom-block"};function m(f,e,y,b,_,w){const o=l("Badge");return i(),r("div",null,[e[2]||(e[2]=a('<h2 id="launching-linux-rescue-shell" tabindex="-1">Launching Linux Rescue Shell <a class="header-anchor" href="#launching-linux-rescue-shell" aria-label="Permalink to &quot;Launching Linux Rescue Shell&quot;">​</a></h2><p>After that, either launch your payload with a payload website to load them, or use &quot;Payload Guest&quot; app if the website doesn&#39;t work for you.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Remember that the amount of VRAM you allocate is taken from your system memory! For a 2GB of VRAM payload, you&#39;d have 8-2 = 6GB of remaining system RAM! You aren&#39;t creating memory out of thin air.</p></div><h3 id="payload-website-hosts" tabindex="-1">Payload website hosts <a class="header-anchor" href="#payload-website-hosts" aria-label="Permalink to &quot;Payload website hosts&quot;">​</a></h3>',4)),t("details",h,[t("summary",null,[e[0]||(e[0]=n("Firmware ",-1)),d(o,{type:"tip",text:"7.00 - 13.02"})]),e[1]||(e[1]=a('<div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>You MUST use a 1GB VRAM payload for installation and first boot. Afterwards, 2GB is recommended.</p></div><p>Follow these steps:</p><ul><li>Go to <a href="http://psfree-enhanced.free.nf/" target="_blank" rel="noreferrer">psfree-enhanced.free.nf</a></li><li>Select Linux tab at the top center <ul><li>Wait for the cache to finish installing!</li></ul></li><li>Load your desired payload <ul><li>Again, 1GB is necessary for first time installation!</li><li>If you use the PS4 as a server after installation, switch to one of the server payloads for more system RAM.</li></ul></li></ul><img src="'+u+'" width="75%">',4))]),e[3]||(e[3]=a('<details class="details custom-block"><summary>Alternative website (FW 5.05+)</summary><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>You MUST use a 1GB VRAM payload for installation and first boot. Afterwards, 2GB is recommended.</p></div><img src="'+c+'" width="75%"><p>Even though this website is probably not maintained anymore it&#39;ll stay here, as the newer website doesn&#39;t work on low firmwares.</p><ul><li><a href="https://ps4boot.github.io/" target="_blank" rel="noreferrer">ps4boot.github.io</a> (5.05/6.72/9.60) (Webkit method)</li><li><a href="http://ps4boot.free.nfl" target="_blank" rel="noreferrer">ps4boot.free.nf</a> (5.05-12.02) (GoldHEN method, works only with HTTP not HTTPS)</li></ul></details><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you wanna use it as a server you have to make a vram.txt file where the kernel and initramfs is and type <code>128</code> mb, lower values will cause display issues.</p></div><p>If the website doesn&#39;t work, use the Payload Guest local method below.</p><h3 id="local-payloads" tabindex="-1">Local payloads <a class="header-anchor" href="#local-payloads" aria-label="Permalink to &quot;Local payloads&quot;">​</a></h3><p>If you so desire, or you can&#39;t launch it from the web browser for some reason, it&#39;s possible to load these payloads locally.</p><p>In order to do that, you need to download them <a href="https://github.com/ArabPixel/ps4-linux-payloads/releases/" target="_blank" rel="noreferrer">here</a>.</p><h4 id="local-payloads-setup" tabindex="-1">Local payloads setup <a class="header-anchor" href="#local-payloads-setup" aria-label="Permalink to &quot;Local payloads setup&quot;">​</a></h4><ul><li>Install &quot;Payload Guest&quot; or similar app on your PS4 to load the payloads locally</li><li>Extract from the ELF folders, and rename the file to have a <code>.bin</code> extension instead of <code>.elf</code>, because Payload Loader can&#39;t load ELFs <ul><li>Using the <code>.elf</code> seems to lead to a higher success rate when launching</li><li>Enable &quot;see file extensions&quot; on Windows Explorer or what you&#39;re using</li></ul></li><li>Put the files in the <code>/data/payloads/</code> directory</li><li>Remember to check here sometimes to see if there&#39;s any updates</li></ul>',8))])}const P=s(p,[["render",m]]);export{k as __pageData,P as default};
